// Edge Function : resolve-arc-boss
// BOSS D'ARC : rencontre spéciale qui clôt un arc. La vaincre débloque l'arc
// suivant + son tier de matériaux (ligne player_arc_progress). Réutilise le
// moteur de donjon (simulateDungeonRun) ; calcul 100 % serveur (anti-triche).

import { createClient } from 'jsr:@supabase/supabase-js@2';
import type { CombatantInput } from '@shared/combat/index.ts';
import { buildHeroSnapshot, type HeroSnapshotInput } from '@shared/progression/heroLoan.ts';
import { computeSetBonuses } from '@shared/progression/sets.ts';
import {
  simulateDungeonRun,
  type DungeonType,
  type LootEntry,
  type DungeonFightDef,
} from '@shared/progression/dungeon.ts';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  'Access-Control-Allow-Methods': 'POST, OPTIONS',
};

const MAX_TEAM = 5;

type Body = { arc_boss_id?: unknown; hero_ids?: unknown };

function json(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, 'Content-Type': 'application/json' },
  });
}

// deno-lint-ignore no-explicit-any
type Admin = any;

const HERO_SELECT =
  'id, name, class_id, level, owner_id, alloc_hp, alloc_atk, alloc_def, alloc_speed, skills, ' +
  'bonus_hp, bonus_atk, bonus_def, bonus_speed, ' +
  'cls:hero_classes!heroes_class_id_fkey(base_hp, base_atk, base_def, base_speed), ' +
  'weapon:items!heroes_equipped_weapon_id_fkey(atk_bonus, def_bonus, hp_bonus, set_id), ' +
  'armor:items!heroes_equipped_armor_id_fkey(atk_bonus, def_bonus, hp_bonus, set_id), ' +
  'jewel:items!heroes_equipped_jewel_id_fkey(atk_bonus, def_bonus, hp_bonus, passive_type, passive_value, set_id), ' +
  'relic:items!heroes_equipped_relic_id_fkey(atk_bonus, def_bonus, hp_bonus, set_id)';

// deno-lint-ignore no-explicit-any
function toSnapshotInput(h: any): HeroSnapshotInput {
  const cls = h.cls;
  const sum = (k: string) =>
    (h.weapon?.[k] ?? 0) + (h.armor?.[k] ?? 0) + (h.jewel?.[k] ?? 0) + (h.relic?.[k] ?? 0);
  const setB = computeSetBonuses([h.weapon?.set_id, h.armor?.set_id, h.jewel?.set_id, h.relic?.set_id]);
  return {
    id: h.id,
    name: h.name,
    classId: h.class_id,
    level: h.level,
    classBase: { hp: cls.base_hp, atk: cls.base_atk, def: cls.base_def, speed: cls.base_speed },
    innate: { hp: h.bonus_hp ?? 0, atk: h.bonus_atk ?? 0, def: h.bonus_def ?? 0, speed: h.bonus_speed ?? 0 },
    alloc: { hp: h.alloc_hp, atk: h.alloc_atk, def: h.alloc_def, speed: h.alloc_speed },
    equipment: { atk: sum('atk_bonus') + setB.atk, def: sum('def_bonus') + setB.def, hp: sum('hp_bonus') + setB.hp },
    jewelPassive:
      h.jewel?.passive_type && (h.jewel?.passive_value ?? 0) > 0
        ? { type: h.jewel.passive_type, value: h.jewel.passive_value / 100 }
        : null,
    skills: (h.skills ?? {}) as Record<string, number>,
  };
}

/** Héros engagés dans une activité idle (farm 'loop' ou expédition en cours). */
async function engagedInActivity(admin: Admin): Promise<Set<string>> {
  const engaged = new Set<string>();
  const { data: deps } = await admin.from('deployments').select('hero_ids').eq('mode', 'loop');
  for (const r of deps ?? []) for (const h of (r.hero_ids as string[]) ?? []) engaged.add(h);
  const { data: exps } = await admin
    .from('expedition_runs')
    .select('hero_ids')
    .eq('status', 'in_progress');
  for (const r of exps ?? []) for (const h of (r.hero_ids as string[]) ?? []) engaged.add(h);
  return engaged;
}

async function addResources(
  admin: Admin,
  userId: string,
  resources: Record<string, number>,
): Promise<void> {
  for (const [resource, add] of Object.entries(resources)) {
    if (add <= 0) continue;
    const { data: row } = await admin
      .from('player_resources')
      .select('amount')
      .eq('player_id', userId)
      .eq('resource', resource)
      .maybeSingle();
    await admin
      .from('player_resources')
      .upsert(
        { player_id: userId, resource, amount: (row?.amount ?? 0) + add },
        { onConflict: 'player_id,resource' },
      );
  }
}

// deno-lint-ignore no-explicit-any
function toDungeonType(row: any): DungeonType {
  return {
    id: row.id,
    name: row.name,
    tier: row.tier,
    monsterSequence: (row.monster_sequence ?? []) as DungeonFightDef[],
    regenPctBetweenFights: Number(row.regen_pct_between_fights),
    minibossIndices: (row.miniboss_indices ?? []) as number[],
    bossIndex: row.boss_index,
    lootTableNormal: (row.loot_table_normal ?? []) as LootEntry[],
    lootTableMiniboss: (row.loot_table_miniboss ?? []) as LootEntry[],
    lootTableBoss: (row.loot_table_boss ?? []) as LootEntry[],
  };
}

Deno.serve(async (req: Request) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
  if (req.method !== 'POST') return json({ error: 'Méthode non autorisée' }, 405);

  const supabaseUrl = Deno.env.get('SUPABASE_URL');
  const anonKey = Deno.env.get('SUPABASE_ANON_KEY');
  const serviceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
  if (!supabaseUrl || !anonKey || !serviceKey)
    return json({ error: 'Config serveur manquante' }, 500);

  const authHeader = req.headers.get('Authorization');
  if (!authHeader) return json({ error: 'Non authentifié' }, 401);

  const userClient = createClient(supabaseUrl, anonKey, {
    global: { headers: { Authorization: authHeader } },
  });
  const {
    data: { user },
    error: userError,
  } = await userClient.auth.getUser();
  if (userError || !user) return json({ error: 'Session invalide' }, 401);

  let body: Body;
  try {
    body = (await req.json()) as Body;
  } catch {
    return json({ error: 'Corps de requête invalide' }, 400);
  }
  const arcBossId = body.arc_boss_id;
  const heroIds = body.hero_ids;
  if (typeof arcBossId !== 'string') return json({ error: 'arc_boss_id invalide' }, 400);
  if (!Array.isArray(heroIds) || heroIds.some((h) => typeof h !== 'string')) {
    return json({ error: 'hero_ids invalide' }, 400);
  }
  const unique = [...new Set(heroIds as string[])];
  if (unique.length < 1 || unique.length > MAX_TEAM) {
    return json({ error: `Entre 1 et ${MAX_TEAM} héros` }, 400);
  }

  const admin: Admin = createClient(supabaseUrl, serviceKey, { auth: { persistSession: false } });

  // --- Boss d'arc ---
  const { data: bossRow, error: bossErr } = await admin
    .from('arc_bosses')
    .select('*')
    .eq('id', arcBossId)
    .single();
  if (bossErr || !bossRow) return json({ error: "Boss d'arc introuvable" }, 404);

  // Déjà vaincu ? (le gate est à sens unique)
  const { data: already } = await admin
    .from('player_arc_progress')
    .select('gate_boss_id')
    .eq('player_id', user.id)
    .eq('gate_boss_id', arcBossId)
    .maybeSingle();
  if (already) return json({ error: 'Boss d’arc déjà vaincu' }, 409);

  // Arc « prêt » : la dernière zone de l'arc doit être terminée.
  if (bossRow.required_level_id) {
    const { data: prog } = await admin
      .from('level_progress')
      .select('level_id')
      .eq('player_id', user.id)
      .eq('level_id', bossRow.required_level_id)
      .maybeSingle();
    if (!prog) {
      return json({ error: "Termine d'abord toutes les zones de l'arc" }, 403);
    }
  }

  const boss = toDungeonType(bossRow);
  if (boss.monsterSequence.length === 0) {
    return json({ error: "Boss d'arc mal configuré (séquence vide)" }, 400);
  }

  // --- Héros possédés et disponibles ---
  const { data: heroRows } = await admin
    .from('heroes')
    .select(HERO_SELECT)
    .in('id', unique)
    .eq('owner_id', user.id);
  if (!heroRows || heroRows.length !== unique.length) {
    return json({ error: 'Héros introuvables ou non possédés' }, 404);
  }
  const engaged = await engagedInActivity(admin);
  for (const h of heroRows) {
    if (engaged.has(h.id)) {
      return json({ error: 'Un héros est déjà engagé dans une autre activité' }, 409);
    }
  }

  // --- Escouade + simulation serveur ---
  const snapshotById = new Map<string, CombatantInput>(
    // deno-lint-ignore no-explicit-any
    (heroRows as any[]).map((h) => [h.id, buildHeroSnapshot(toSnapshotInput(h))]),
  );
  const squad: CombatantInput[] = unique.map((id) => snapshotById.get(id)!);
  const seed = Math.floor(Math.random() * 2_147_483_647);
  const run = simulateDungeonRun(seed, squad, boss);

  // --- Victoire : débloque l'arc suivant + crédite le butin ---
  if (run.success) {
    await admin
      .from('player_arc_progress')
      .upsert(
        { player_id: user.id, gate_boss_id: arcBossId },
        { onConflict: 'player_id,gate_boss_id' },
      );
    const lootMap: Record<string, number> = {};
    for (const drop of run.lootRolled) lootMap[drop.resource] = drop.amount;
    await addResources(admin, user.id, lootMap);
  }

  return json({
    success: run.success,
    reached_index: run.reachedIndex,
    seed,
    arc_boss: { id: boss.id, name: boss.name, unlocks_tier: bossRow.unlocks_tier },
    fight_results: run.fightResults,
    loot: run.success ? run.lootRolled : [],
  });
});

/**
 * Réglages de difficulté des ENNEMIS, partagés front + Edge Functions.
 *
 * Deux règles, appliquées au moment où l'on construit les combattants ennemis :
 *  1. Les monstres « classiques » (mobs normaux, hors mini-boss et boss) sont
 *     renforcés (PV / ATK / DEF) — les combats de progression étaient trop faciles.
 *  2. Les boss sont insensibles à l'étourdissement (stun) : on ne peut pas les
 *     bloquer en boucle. Leurs stats restent inchangées (déjà équilibrées).
 *
 * Primitives PURES : pas d'I/O, ne mutent pas leurs entrées (renvoient une copie).
 */
import type { Ability, CombatantInput } from './types.ts';

/** Multiplicateurs de stats appliqués à un ennemi. */
export type MonsterScaling = { hp: number; atk: number; def: number };

/**
 * Multiplicateurs appliqués aux monstres classiques (mobs normaux).
 * Ajuster ici pour recalibrer globalement la difficulté des combats de base.
 */
export const NORMAL_MONSTER_SCALING: MonsterScaling = {
  hp: 1.6,
  atk: 1.35,
  def: 1.3,
};

/**
 * Multiplicateurs appliqués aux mini-boss (checkpoint d'une séquence de donjon).
 * Renforcés eux aussi, mais plus légèrement : ils partent déjà d'un socle plus
 * élevé et restent en dessous du boss final.
 */
export const MINIBOSS_MONSTER_SCALING: MonsterScaling = {
  hp: 1.35,
  atk: 1.2,
  def: 1.2,
};

/** Applique un jeu de multiplicateurs à un ennemi (copie, ne mute pas l'entrée). */
function scaleMonster(m: CombatantInput, mult: MonsterScaling): CombatantInput {
  const scaled: CombatantInput = {
    ...m,
    hp: Math.max(1, Math.round(m.hp * mult.hp)),
    atk: Math.max(1, Math.round(m.atk * mult.atk)),
    def: Math.max(0, Math.round(m.def * mult.def)),
  };
  // startHp suit hp (un mob démarre plein) — jamais fourni côté ennemi
  // aujourd'hui, mais on le scale par cohérence s'il l'était un jour.
  if (m.startHp != null) {
    scaled.startHp = Math.max(1, Math.round(m.startHp * mult.hp));
  }
  return scaled;
}

/** Renforce un monstre classique : plus de PV, d'ATK et de DEF. */
export function scaleNormalMonster(m: CombatantInput): CombatantInput {
  return scaleMonster(m, NORMAL_MONSTER_SCALING);
}

/** Renforce un mini-boss (boost plus modéré que les mobs classiques). */
export function scaleMinibossMonster(m: CombatantInput): CombatantInput {
  return scaleMonster(m, MINIBOSS_MONSTER_SCALING);
}

/** Abilité rendant totalement insensible à l'étourdissement (stun). */
const STUN_IMMUNITY: Ability = { kind: 'immune', chance: 1, statuses: ['stun'] };

/** Rend un boss insensible au stun (sans dupliquer l'immunité si déjà présente). */
export function withStunImmunity(m: CombatantInput): CombatantInput {
  const abilities = m.abilities ?? [];
  const alreadyImmune = abilities.some(
    (a) =>
      a.kind === 'immune' &&
      a.chance >= 1 &&
      (a.statuses == null || a.statuses.includes('stun')),
  );
  if (alreadyImmune) return m;
  return { ...m, abilities: [...abilities, STUN_IMMUNITY] };
}

/**
 * PRNG déterministe (mulberry32). Même seed → même séquence.
 * Permet de rejouer/déboguer un combat et d'écrire des tests déterministes.
 * Pur, sans dépendance runtime (importable côté Vite ET côté Deno).
 */
export type Rng = {
  /** Flottant dans [0, 1). */
  next(): number;
  /** Entier dans [min, max] inclus. */
  int(min: number, max: number): number;
  /** Facteur de variance dans [1 - spread, 1 + spread). */
  variance(spread: number): number;
};

export function createRng(seed: number): Rng {
  let a = seed >>> 0;

  const next = (): number => {
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };

  return {
    next,
    int: (min, max) => min + Math.floor(next() * (max - min + 1)),
    variance: (spread) => 1 - spread + next() * (2 * spread),
  };
}

import { createRng, type Rng } from './prng.ts';
import type {
  Ability,
  CombatEvent,
  CombatInput,
  CombatResult,
  CombatantFinalState,
  CombatantInput,
  MarkType,
  PassiveType,
  Side,
  StatusType,
} from './types.ts';

const DEFAULT_MAX_ROUNDS = 100;
const DAMAGE_VARIANCE = 0.15;
const HEAL_MULTIPLIER = 1.5;
/** Plafond de pénétration d'armure (on ne peut pas ignorer plus de 90 % de la mitigation). */
const ARMOR_PEN_CAP = 0.9;

/** Statut actif sur un combattant (runtime). */
type ActiveStatus = {
  type: StatusType;
  turnsLeft: number;
  /** DoT : dégâts par tour (poison/burn). */
  dmgPerTurn: number;
  /** weaken : fraction de réduction ATK/DEF. */
  weaken: number;
  /** Nom de la source (pour les messages). */
  sourceName: string;
  /** Id de la source (pour la propagation / contagion). */
  sourceId: string;
};

/** Buff temporaire à durée (fraction cumulée par champ, décrémenté chaque manche). */
type TimedBuff = {
  turnsLeft: number;
  atk?: number;
  def?: number;
  speed?: number;
  dmg?: number;
  reduce?: number;
  thornsMult?: number;
  reflect?: number;
  heal?: number;
};

type Fighter = CombatantInput & {
  side: Side;
  order: number; // index stable pour départager à vitesse égale
  maxHp: number;
  hp: number;
  alive: boolean;
  statuses: ActiveStatus[];
  reviveUsed: boolean;
  /** Compteurs de marques cumulables (feu empilable, marque arcanique). */
  stacks: Record<MarkType, number>;
  /** Barrière absorbante courante (PV temporaires, regénérée chaque tour). */
  barrier: number;
  /** Buffs temporaires actifs (auras chronométrées, renvoi, etc.). */
  buffs: TimedBuff[];
};

/** Somme d'un champ de buff sur tous les buffs actifs d'un combattant. */
function buffSum(f: Fighter, key: keyof Omit<TimedBuff, 'turnsLeft'>): number {
  let total = 0;
  for (const b of f.buffs) if (b.turnsLeft > 0) total += b[key] ?? 0;
  return total;
}

/** Statuts considérés « négatifs » (ciblés par l'immunité). */
const NEGATIVE_STATUSES: StatusType[] = ['poison', 'burn', 'stun', 'weaken'];

/** Somme des valeurs d'un passif sur un combattant (0 si absent). */
function passive(f: Fighter, type: PassiveType): number {
  let total = 0;
  for (const p of f.passives ?? []) if (p.type === type) total += p.value;
  return total;
}

function abilitiesOf(f: Fighter, kind: Ability['kind']): Ability[] {
  return (f.abilities ?? []).filter((a) => a.kind === kind);
}

function hasStatus(f: Fighter, type: StatusType): boolean {
  return f.statuses.some((s) => s.type === type && s.turnsLeft > 0);
}

/** Fraction de mitigation ignorée par les abilités armor_pen (plafonnée). */
function armorPenOf(f: Fighter): number {
  let total = 0;
  for (const a of abilitiesOf(f, 'armor_pen')) if (a.kind === 'armor_pen') total += a.value;
  return Math.min(ARMOR_PEN_CAP, total);
}

/** Réduction ATK/DEF cumulée des statuts weaken (plafonnée à 90 %). */
function weakenOf(f: Fighter): number {
  let total = 0;
  for (const s of f.statuses) if (s.type === 'weaken' && s.turnsLeft > 0) total += s.weaken;
  return Math.min(0.9, total);
}

function effectiveAtk(f: Fighter): number {
  return Math.max(1, Math.round(f.atk * (1 + buffSum(f, 'atk')) * (1 - weakenOf(f))));
}

/** Vitesse effective (buffs temporaires inclus) pour l'ordre d'action. */
function effectiveSpeed(f: Fighter): number {
  return f.speed * (1 + buffSum(f, 'speed'));
}

/** Mitigation totale = (DEF + armure) × (1 − weaken), réduite par la pénétration de l'attaquant. */
function mitigation(target: Fighter, attacker: Fighter): number {
  const def = Math.max(0, target.def * (1 + buffSum(target, 'def')));
  const raw = (def + (target.armor ?? 0)) * (1 - weakenOf(target));
  return Math.max(0, raw * (1 - armorPenOf(attacker)));
}

/** Bonus de dégâts si la cible est affligée d'un statut ciblé par amp_vs_status. */
function ampVsStatus(actor: Fighter, target: Fighter): number {
  let bonus = 0;
  for (const a of abilitiesOf(actor, 'amp_vs_status')) {
    if (a.kind === 'amp_vs_status' && hasStatus(target, a.status)) bonus += a.bonus;
  }
  return bonus;
}

/**
 * Applique les bonus de stats permanents (`stat_mod`) au setup : auras d'équipe
 * (scope 'team', partagées par tout le camp) + buffs personnels (scope 'self').
 * value = fraction cumulée par stat. Renvoie de nouveaux inputs aux stats boostées.
 */
function applyAuras(inputs: CombatantInput[]): CombatantInput[] {
  const team = { atk: 0, def: 0, hp: 0 };
  for (const c of inputs) {
    for (const a of c.abilities ?? []) {
      if (a.kind === 'stat_mod' && a.scope === 'team') team[a.stat] += a.value;
    }
  }
  const hasAny = team.atk > 0 || team.def > 0 || team.hp > 0
    || inputs.some((c) => (c.abilities ?? []).some((a) => a.kind === 'stat_mod' && a.scope === 'self'));
  if (!hasAny) return inputs;

  return inputs.map((c) => {
    const self = { atk: 0, def: 0, hp: 0 };
    for (const a of c.abilities ?? []) {
      if (a.kind === 'stat_mod' && a.scope === 'self') self[a.stat] += a.value;
    }
    const mult = (stat: 'atk' | 'def' | 'hp'): number => 1 + team[stat] + self[stat];
    const scaled: CombatantInput = {
      ...c,
      atk: Math.max(1, Math.round(c.atk * mult('atk'))),
      def: Math.round(c.def * mult('def')),
      hp: Math.max(1, Math.round(c.hp * mult('hp'))),
    };
    // Conserve la proportion de PV en cours (donjons multi-combats) sans forcer la clé.
    if (c.startHp !== undefined) scaled.startHp = Math.max(0, Math.round(c.startHp * mult('hp')));
    return scaled;
  });
}

function buildFighters(inputs: CombatantInput[], side: Side, offset: number): Fighter[] {
  return inputs.map((c, i) => {
    const maxHp = c.hp;
    // PV de départ : `startHp` si fourni (donjons multi-combats), sinon plein.
    const hp = Math.max(0, Math.min(maxHp, c.startHp ?? maxHp));
    return {
      ...c,
      side,
      order: offset + i,
      maxHp,
      hp,
      alive: hp > 0,
      statuses: [],
      reviveUsed: false,
      stacks: { burn: 0, arcane: 0 },
      barrier: 0,
      buffs: [],
    };
  });
}

/** Ordre d'action : vitesse décroissante, puis alliés d'abord, puis ordre d'entrée. */
function turnOrder(fighters: Fighter[]): Fighter[] {
  return [...fighters].sort((a, b) => {
    const sa = effectiveSpeed(a);
    const sb = effectiveSpeed(b);
    if (sb !== sa) return sb - sa;
    if (a.side !== b.side) return a.side === 'ally' ? -1 : 1;
    return a.order - b.order;
  });
}

function livingOnSide(fighters: Fighter[], side: Side): Fighter[] {
  return fighters.filter((f) => f.side === side && f.alive);
}

/**
 * Choisit la cible d'un attaquant parmi `candidates` (ennemis vivants).
 * 1. Provocation : si des cibles provoquent, on ne vise qu'elles.
 * 2. `random` (attaques ennemies) : cible tirée au hasard, pour ne pas
 *    achever systématiquement le plus fragile (le mage mourait toujours en 1er).
 * 3. sinon (attaques alliées) : focus fire sur le plus bas PV (départage par ordre).
 */
function threatOf(f: Fighter): number {
  let t = 0;
  for (const a of f.abilities ?? []) if (a.kind === 'threat') t += a.value;
  return Math.max(0, t);
}

function pickTarget(candidates: Fighter[], random: boolean, rng: Rng): Fighter | null {
  if (candidates.length === 0) return null;
  const taunters = candidates.filter((f) => hasStatus(f, 'taunt'));
  const pool = taunters.length > 0 ? taunters : candidates;
  if (random) {
    // Sans menace (agro), tirage uniforme (comportement historique inchangé).
    const totalThreat = pool.reduce((s, f) => s + threatOf(f), 0);
    if (totalThreat <= 0) return pool[rng.int(0, pool.length - 1)] ?? null;
    // Sinon, tirage pondéré par la menace (1 + threat).
    const weights = pool.map((f) => 1 + threatOf(f));
    const total = weights.reduce((s, w) => s + w, 0);
    let r = rng.next() * total;
    for (let i = 0; i < pool.length; i++) {
      r -= weights[i]!;
      if (r < 0) return pool[i]!;
    }
    return pool[pool.length - 1] ?? null;
  }
  return pool.reduce((best, f) => {
    if (f.hp < best.hp) return f;
    if (f.hp === best.hp && f.order < best.order) return f;
    return best;
  });
}

/** Allié le plus blessé (PV manquants max), null si tout le monde est au max. */
function pickHealTarget(allies: Fighter[]): Fighter | null {
  const wounded = allies.filter((f) => f.hp < f.maxHp);
  if (wounded.length === 0) return null;
  return wounded.reduce((best, f) => {
    const missing = f.maxHp - f.hp;
    const bestMissing = best.maxHp - best.hp;
    if (missing > bestMissing) return f;
    if (missing === bestMissing && f.order < best.order) return f;
    return best;
  });
}

const STATUS_LABEL: Record<StatusType, string> = {
  poison: 'empoisonné',
  burn: 'en feu',
  stun: 'étourdi',
  weaken: 'affaibli',
  taunt: 'provocateur',
};

/**
 * Résout un combat de façon déterministe pour une seed donnée.
 * Fonction pure : aucune I/O, aucune dépendance runtime.
 */
export function resolveCombat(input: CombatInput): CombatResult {
  const maxRounds = input.maxRounds ?? DEFAULT_MAX_ROUNDS;
  const rng = createRng(input.seed);

  const allies = buildFighters(applyAuras(input.allies), 'ally', 0);
  const enemies = buildFighters(applyAuras(input.enemies), 'enemy', input.allies.length);
  const fighters = [...allies, ...enemies];
  const byId = new Map(fighters.map((f) => [f.id, f]));

  const events: CombatEvent[] = [];
  let round = 0;

  /** Chance de contagion (propagation des DoT) d'un combattant, 0 si absent. */
  const contagionOf = (f: Fighter): number => {
    let c = 0;
    for (const a of abilitiesOf(f, 'contagion')) if (a.kind === 'contagion') c = Math.max(c, a.chance);
    return c;
  };

  const sideCleared = (side: Side): boolean => livingOnSide(fighters, side).length === 0;

  /** Applique des dégâts bruts (déjà calculés) à une cible + gère mort/résurrection. */
  const applyDamage = (actor: Fighter, target: Fighter, damage: number, message: string): void => {
    let dealt = damage;
    // Réduction temporaire des dégâts subis (Vengeance du damné…).
    const reduce = Math.min(0.9, buffSum(target, 'reduce'));
    if (reduce > 0 && dealt > 0) dealt = Math.max(1, Math.round(dealt * (1 - reduce)));
    // Barrière : absorbe ensuite (PV temporaires).
    if (target.barrier > 0 && dealt > 0) {
      const absorbed = Math.min(target.barrier, dealt);
      target.barrier -= absorbed;
      dealt -= absorbed;
    }
    target.hp = Math.max(0, target.hp - dealt);
    events.push({
      type: 'attack',
      round,
      actorId: actor.id,
      targetId: target.id,
      damage: dealt,
      targetHpAfter: target.hp,
      message,
    });
    if (target.hp === 0 && target.alive) killOrRevive(target);
  };

  const killOrRevive = (f: Fighter): void => {
    // Passif Renaissance (Paladin) : une fois par combat, revient à hpPct.
    const revive = abilitiesOf(f, 'revive').find((a) => a.kind === 'revive');
    if (revive && revive.kind === 'revive' && !f.reviveUsed) {
      f.reviveUsed = true;
      f.hp = Math.max(1, Math.round(f.maxHp * revive.hpPct));
      f.statuses = [];
      events.push({
        type: 'heal',
        round,
        actorId: f.id,
        targetId: f.id,
        amount: f.hp,
        targetHpAfter: f.hp,
        message: `${f.name} renaît à ${f.hp} PV`,
      });
      return;
    }
    f.alive = false;
    events.push({ type: 'death', round, combatantId: f.id, message: `${f.name} est vaincu` });
  };

  /** Applique (ou rafraîchit) un statut sur une cible. */
  /** Immunité : chance d'ignorer un statut négatif entrant (Paladin Bastion). */
  const resistsStatus = (target: Fighter, type: StatusType): boolean => {
    if (!NEGATIVE_STATUSES.includes(type)) return false;
    for (const a of abilitiesOf(target, 'immune')) {
      if (a.kind !== 'immune') continue;
      if (a.statuses && !a.statuses.includes(type)) continue;
      if (rng.next() < a.chance) return true;
    }
    return false;
  };

  const applyStatus = (
    source: Fighter,
    target: Fighter,
    type: StatusType,
    potency: number,
    duration: number,
  ): void => {
    if (!target.alive || duration <= 0) return;
    if (resistsStatus(target, type)) {
      events.push({
        type: 'status',
        round,
        combatantId: target.id,
        status: type,
        message: `${target.name} résiste à l'effet ${STATUS_LABEL[type]}`,
      });
      return;
    }
    const dmgPerTurn =
      type === 'poison' || type === 'burn'
        ? Math.max(1, Math.round(effectiveAtk(source) * potency))
        : 0;
    const weaken = type === 'weaken' ? potency : 0;
    applyStatusRaw(target, {
      type,
      turnsLeft: duration,
      dmgPerTurn,
      weaken,
      sourceName: source.name,
      sourceId: source.id,
    });
  };

  /** Applique/rafraîchit un statut déjà calculé (utilisé aussi par la contagion). */
  const applyStatusRaw = (target: Fighter, s: ActiveStatus): void => {
    if (!target.alive || s.turnsLeft <= 0) return;
    const existing = target.statuses.find((x) => x.type === s.type);
    if (existing) {
      existing.turnsLeft = Math.max(existing.turnsLeft, s.turnsLeft);
      existing.dmgPerTurn = Math.max(existing.dmgPerTurn, s.dmgPerTurn);
      existing.weaken = Math.max(existing.weaken, s.weaken);
      existing.sourceName = s.sourceName;
      existing.sourceId = s.sourceId;
    } else {
      target.statuses.push({ ...s });
    }
    events.push({
      type: 'status',
      round,
      combatantId: target.id,
      status: s.type,
      message: `${target.name} est ${STATUS_LABEL[s.type]}`,
    });
  };

  /** Déclenche les procs "on_hit" de l'attaquant sur une cible touchée. */
  const applyOnHitProcs = (actor: Fighter, target: Fighter): void => {
    if (!target.alive) return;
    for (const a of abilitiesOf(actor, 'on_hit')) {
      if (a.kind !== 'on_hit') continue;
      if (rng.next() < a.chance) applyStatus(actor, target, a.status, a.potency, a.duration);
    }
  };

  /** Résout une attaque simple d'`actor` sur `target` (avec passifs & procs). */
  const basicAttack = (actor: Fighter, target: Fighter): void => {
    // Passif Esquive : la cible peut annuler complètement l'attaque.
    const dodge = passive(target, 'dodge');
    if (dodge > 0 && rng.next() < dodge) {
      events.push({
        type: 'attack',
        round,
        actorId: actor.id,
        targetId: target.id,
        damage: 0,
        targetHpAfter: target.hp,
        message: `${target.name} esquive l'attaque de ${actor.name}`,
      });
      return;
    }

    // Multiplicateurs offensifs conditionnels (passifs de l'attaquant + amp abilité).
    let mult = 1 + ampVsStatus(actor, target);
    // +dégâts par stack de marque présente sur la cible (combustion, marque arcanique).
    for (const a of abilitiesOf(actor, 'amp_per_stack')) {
      if (a.kind === 'amp_per_stack') mult += a.bonus * (target.stacks[a.mark] ?? 0);
    }
    const rage = passive(actor, 'rage');
    if (rage > 0 && actor.hp < actor.maxHp * 0.5) mult += rage;
    const venom = passive(actor, 'venom');
    if (venom > 0 && target.hp < target.maxHp) mult += venom;
    const firstStrike = passive(actor, 'first_strike');
    if (firstStrike > 0 && round === 1) mult += firstStrike;
    const execute = passive(actor, 'execute');
    if (execute > 0 && target.hp < target.maxHp * 0.3) mult += execute;
    // Buffs temporaires de dégâts (rage d'équipe, Concert céleste…).
    mult += buffSum(actor, 'dmg');

    const barrierBefore = target.barrier;
    const base = Math.max(1, effectiveAtk(actor) - mitigation(target, actor));
    let damage = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE) * mult));

    const crit = passive(actor, 'crit');
    const isCrit = crit > 0 && rng.next() < crit;
    if (isCrit) damage *= 2;

    const shield = passive(target, 'shield');
    if (shield > 0) damage = Math.max(1, Math.round(damage * (1 - shield)));

    applyDamage(
      actor,
      target,
      damage,
      `${actor.name} attaque ${target.name} — ${damage} dégâts${isCrit ? ' CRITIQUE' : ''}`,
    );

    // Procs "on_hit" : appliquent un statut à la cible touchée.
    applyOnHitProcs(actor, target);

    // Marques cumulables (feu empilable / marque arcanique) + détonation au seuil.
    if (target.alive) {
      for (const a of abilitiesOf(actor, 'stack_on_hit')) {
        if (a.kind !== 'stack_on_hit') continue;
        if (rng.next() < a.chance) {
          target.stacks[a.mark] = Math.min(a.max, (target.stacks[a.mark] ?? 0) + 1);
        }
      }
      for (const a of abilitiesOf(actor, 'detonate')) {
        if (a.kind !== 'detonate') continue;
        if ((target.stacks[a.mark] ?? 0) >= a.threshold) {
          const burst = Math.max(1, Math.round(effectiveAtk(actor) * a.dmgMult));
          target.stacks[a.mark] = 0;
          applyDamage(actor, target, burst, `${actor.name} fait exploser ${target.name} — ${burst} dégâts`);
        }
      }
    }

    // Contrecoup : si la barrière de la cible vient d'être brisée, elle riposte.
    if (target.alive && barrierBefore > 0 && target.barrier === 0) {
      for (const a of abilitiesOf(target, 'riposte_shield')) {
        if (a.kind !== 'riposte_shield') continue;
        const rip = Math.max(1, Math.round(damage * a.bonus));
        applyDamage(target, actor, rip, `${target.name} riposte à ${actor.name} — ${rip} dégâts`);
      }
    }

    // Passif Vampirisme : l'attaquant se soigne d'une part des dégâts.
    const lifesteal = passive(actor, 'lifesteal');
    if (lifesteal > 0 && actor.hp < actor.maxHp && actor.alive) {
      const amount = Math.min(actor.maxHp - actor.hp, Math.max(1, Math.round(damage * lifesteal)));
      actor.hp += amount;
      events.push({
        type: 'heal',
        round,
        actorId: actor.id,
        targetId: actor.id,
        amount,
        targetHpAfter: actor.hp,
        message: `${actor.name} draine ${amount} PV`,
      });
    }

    // Épines : renvoi d'une part des dégâts (amplifié par Miroir, ou renvoi total par Vengeance).
    const thornsBase = passive(target, 'thorns') * (1 + buffSum(target, 'thornsMult'));
    const reflectFrac = Math.max(thornsBase, buffSum(target, 'reflect'));
    if (reflectFrac > 0 && target.alive) {
      const reflected = Math.max(1, Math.round(damage * reflectFrac));
      applyDamage(
        target,
        actor,
        reflected,
        `Les épines de ${target.name} renvoient ${reflected} dégâts à ${actor.name}`,
      );
    }
  };

  /** Multiplicateur de soin de l'acteur (abilités heal_amp). */
  const healAmpOf = (f: Fighter): number => {
    let b = 0;
    for (const a of abilitiesOf(f, 'heal_amp')) if (a.kind === 'heal_amp') b += a.bonus;
    return 1 + b;
  };

  /** Soigne une cible ; renvoie le montant réellement rendu. */
  const heal = (actor: Fighter, target: Fighter, amount: number, message: string): number => {
    const preHp = target.hp;
    const newHp = Math.min(target.maxHp, target.hp + Math.max(0, amount));
    const gained = newHp - target.hp;
    target.hp = newHp;
    if (gained > 0) {
      events.push({
        type: 'heal',
        round,
        actorId: actor.id,
        targetId: target.id,
        amount: gained,
        targetHpAfter: target.hp,
        message: `${message} — ${gained} PV`,
      });
      // Second souffle : soigner un allié sous 50 % PV lui octroie de l'ATK temporaire.
      if (preHp < target.maxHp * 0.5) {
        for (const a of abilitiesOf(actor, 'heal_buff')) {
          if (a.kind === 'heal_buff') target.buffs.push({ turnsLeft: a.duration, atk: a.atk });
        }
      }
    }
    return gained;
  };

  /** Lance une abilité active (autocast). Renvoie true si l'action a été exécutée. */
  const runAutocast = (actor: Fighter, ability: Ability, enemySide: Side): boolean => {
    if (ability.kind !== 'autocast') return false;
    const action = ability.action;

    // Soin de zone : cible les alliés blessés (propre camp).
    if (action.type === 'heal_all') {
      const wounded = livingOnSide(fighters, actor.side).filter((f) => f.hp < f.maxHp);
      if (wounded.length === 0) return false;
      events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} invoque une lumière bienfaisante` });
      const amp = healAmpOf(actor);
      for (const t of wounded) {
        heal(actor, t, Math.round(t.maxHp * action.pct * amp), `${actor.name} soigne ${t.name}`);
      }
      return true;
    }

    // Buff temporaire (soi ou toute l'équipe) : Rituel, Concert, Miroir, Vengeance.
    if (action.type === 'buff') {
      const recipients = action.scope === 'team' ? livingOnSide(fighters, actor.side) : [actor];
      const b: TimedBuff = { turnsLeft: action.duration };
      for (const k of ['atk', 'def', 'speed', 'dmg', 'reduce', 'thornsMult', 'reflect'] as const) {
        const v = action[k];
        if (typeof v === 'number') b[k] = v;
      }
      events.push({
        type: 'status',
        round,
        combatantId: actor.id,
        message: action.scope === 'team' ? `${actor.name} galvanise l'équipe` : `${actor.name} s'entoure d'une aura`,
      });
      for (const r of recipients) r.buffs.push({ ...b });
      return true;
    }

    const targets = livingOnSide(fighters, enemySide);
    if (targets.length === 0) return false;

    switch (action.type) {
      case 'aoe': {
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} déchaîne une déflagration` });
        for (const t of targets) {
          if (!t.alive) continue;
          const base = Math.max(1, Math.round(effectiveAtk(actor) * action.dmgMult) - mitigation(t, actor));
          const damage = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE)));
          applyDamage(actor, t, damage, `${actor.name} embrase ${t.name} — ${damage} dégâts`);
          if (t.alive && action.status && rng.next() < (action.statusChance ?? 1)) {
            applyStatus(actor, t, action.status, action.statusPotency ?? 0.1, action.statusDuration ?? 3);
          }
          if (t.alive && action.mark) t.stacks[action.mark] = Math.min(99, (t.stacks[action.mark] ?? 0) + 1);
          applyOnHitProcs(actor, t);
        }
        // Propagation du feu : les cibles en feu embrasent toutes les autres.
        if (action.spread && action.status === 'burn') {
          const burning = targets.filter((t) => t.alive && hasStatus(t, 'burn'));
          if (burning.length > 0) {
            for (const t of targets) {
              if (t.alive && !hasStatus(t, 'burn')) {
                applyStatus(actor, t, 'burn', action.statusPotency ?? 0.1, action.statusDuration ?? 3);
              }
            }
          }
        }
        return true;
      }

      case 'stun_all': {
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} invoque une frappe divine` });
        for (const t of targets) {
          if (!t.alive) continue;
          if (action.dmgMult && action.dmgMult > 0) {
            const base = Math.max(1, Math.round(effectiveAtk(actor) * action.dmgMult) - mitigation(t, actor));
            const damage = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE)));
            applyDamage(actor, t, damage, `${actor.name} foudroie ${t.name} — ${damage} dégâts`);
          }
          if (t.alive) {
            applyStatus(actor, t, 'stun', 0, action.duration);
            applyOnHitProcs(actor, t);
          }
        }
        return true;
      }

      case 'nuke': {
        const t = pickTarget(targets, false, rng);
        if (!t) return false;
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} concentre un sort dévastateur` });
        const base = Math.max(1, Math.round(effectiveAtk(actor) * action.dmgMult) - mitigation(t, actor));
        const damage = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE)));
        applyDamage(actor, t, damage, `${actor.name} anéantit ${t.name} — ${damage} dégâts`);
        if (t.alive && action.status) applyStatus(actor, t, action.status, action.statusPotency ?? 0.2, action.statusDuration ?? 2);
        if (t.alive && action.mark) t.stacks[action.mark] = Math.min(99, (t.stacks[action.mark] ?? 0) + 1);
        return true;
      }

      case 'pct_hp': {
        const t = pickTarget(targets, false, rng);
        if (!t) return false;
        // min(PV max × pct, ATK × capMult) : fort sur cibles normales, plafonné sur les boss.
        const dmg = Math.max(
          1,
          Math.min(Math.round(t.maxHp * action.pct), Math.round(effectiveAtk(actor) * action.capMult)),
        );
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} vise un point vital` });
        applyDamage(actor, t, dmg, `${actor.name} transperce ${t.name} — ${dmg} dégâts`);
        return true;
      }

      case 'multi_hit': {
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} déchaîne une rafale` });
        for (let h = 0; h < action.hits; h++) {
          const alive = livingOnSide(fighters, enemySide);
          if (alive.length === 0) break;
          for (const t of alive) {
            const base = Math.max(1, Math.round(effectiveAtk(actor) * action.dmgMult) - mitigation(t, actor));
            const damage = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE)));
            applyDamage(actor, t, damage, `${actor.name} crible ${t.name} — ${damage} dégâts`);
          }
        }
        return true;
      }

      case 'detonate_all': {
        const marked = targets.filter((t) => t.alive && (t.stacks[action.mark] ?? 0) > 0);
        if (marked.length === 0) return false;
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} déclenche une réaction en chaîne` });
        for (const t of marked) {
          const burst = Math.max(1, Math.round(effectiveAtk(actor) * action.dmgMult));
          t.stacks[action.mark] = 0;
          applyDamage(actor, t, burst, `${actor.name} fait exploser ${t.name} — ${burst} dégâts`);
        }
        return true;
      }

      case 'extra_turn': {
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} pousse un cri de désespoir` });
        // Tous les alliés — même ceux à terre — portent une frappe supplémentaire.
        for (const ally of fighters.filter((f) => f.side === actor.side)) {
          const t = pickTarget(livingOnSide(fighters, enemySide), ally.side === 'enemy', rng);
          if (!t) break;
          basicAttack(ally, t);
        }
        return true;
      }

      case 'execute_strike': {
        const t = pickTarget(targets, false, rng);
        if (!t) return false;
        events.push({ type: 'status', round, combatantId: actor.id, message: `${actor.name} rend son jugement` });
        if (t.hp <= t.maxHp * action.instakillPct) {
          applyDamage(actor, t, t.hp, `${actor.name} exécute ${t.name}`);
        } else {
          const base = Math.max(1, Math.round(effectiveAtk(actor) * action.dmgMult) - mitigation(t, actor));
          const damage = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE)));
          applyDamage(actor, t, damage, `${actor.name} juge ${t.name} — ${damage} dégâts`);
        }
        return true;
      }
    }
    return false;
  };

  while (round < maxRounds && !sideCleared('ally') && !sideCleared('enemy')) {
    round += 1;

    // Passif Régénération : chaque combattant vivant récupère X% de ses PV max.
    for (const f of fighters) {
      if (!f.alive) continue;
      const regen = passive(f, 'regen');
      if (regen <= 0 || f.hp >= f.maxHp) continue;
      const amount = Math.min(f.maxHp - f.hp, Math.max(1, Math.round(f.maxHp * regen)));
      f.hp += amount;
      events.push({
        type: 'heal',
        round,
        actorId: f.id,
        targetId: f.id,
        amount,
        targetHpAfter: f.hp,
        message: `${f.name} régénère ${amount} PV`,
      });
    }

    // Barrière (Rempart) : regénérée en début de manche à un % des PV max.
    for (const f of fighters) {
      if (!f.alive) continue;
      let pct = 0;
      for (const a of abilitiesOf(f, 'barrier')) if (a.kind === 'barrier') pct = Math.max(pct, a.pct);
      if (pct > 0) f.barrier = Math.max(f.barrier, Math.round(f.maxHp * pct));
    }

    // Soutien (soigneur / paladin) : soin passif ciblé + barrière sur l'allié le plus faible.
    for (const f of fighters) {
      if (!f.alive) continue;
      const amp = healAmpOf(f);
      for (const a of abilitiesOf(f, 'heal_aura')) {
        if (a.kind !== 'heal_aura') continue;
        const target = pickHealTarget(livingOnSide(fighters, f.side));
        if (target) heal(f, target, Math.round(target.maxHp * a.pct * amp), `${f.name} soigne ${target.name}`);
      }
      for (const a of abilitiesOf(f, 'ally_shield')) {
        if (a.kind !== 'ally_shield') continue;
        if (rng.next() >= a.chance) continue;
        const allies = livingOnSide(fighters, f.side);
        const lowest = pickHealTarget(allies) ?? allies[0];
        if (lowest) {
          lowest.barrier = Math.max(lowest.barrier, Math.round(lowest.maxHp * a.pct));
          events.push({
            type: 'status',
            round,
            combatantId: lowest.id,
            message: `${f.name} protège ${lowest.name} d'une barrière`,
          });
        }
      }
    }

    // Buffs temporisés déclenchés en début de manche.
    for (const f of fighters) {
      if (!f.alive) continue;
      // Fureur du meneur : au tour prévu, +dégâts pour toute l'équipe jusqu'à la fin.
      for (const a of abilitiesOf(f, 'delayed_buff')) {
        if (a.kind === 'delayed_buff' && round === a.afterRounds) {
          for (const ally of livingOnSide(fighters, f.side)) ally.buffs.push({ turnsLeft: maxRounds, dmg: a.dmg });
          events.push({ type: 'status', round, combatantId: f.id, message: `${f.name} déchaîne la fureur de l'équipe` });
        }
      }
      // Bénédiction : chance de poser un soin sur la durée sur toute l'équipe.
      for (const a of abilitiesOf(f, 'team_hot')) {
        if (a.kind !== 'team_hot') continue;
        if (rng.next() >= a.chance) continue;
        for (const ally of livingOnSide(fighters, f.side)) {
          const existing = ally.buffs.find((b) => (b.heal ?? 0) > 0);
          if (existing) existing.turnsLeft = Math.max(existing.turnsLeft, a.duration);
          else ally.buffs.push({ turnsLeft: a.duration, heal: a.pct });
        }
        events.push({ type: 'status', round, combatantId: f.id, message: `${f.name} bénit l'équipe` });
      }
    }

    // Application des soins sur la durée (HoT) en début de manche.
    for (const f of fighters) {
      if (!f.alive) continue;
      const hot = buffSum(f, 'heal');
      if (hot > 0 && f.hp < f.maxHp) heal(f, f, Math.round(f.maxHp * hot), `${f.name} est régénéré par la bénédiction`);
    }

    // Tic des DoT (poison/feu) en début de manche + propagation (contagion).
    const spreads: { target: Fighter; status: ActiveStatus }[] = [];
    for (const f of fighters) {
      if (!f.alive) continue;
      const dots = f.statuses.filter((s) => s.dmgPerTurn > 0 && s.turnsLeft > 0);
      if (dots.length === 0) continue;
      // Un tic par source de DoT : chaque event porte son `sourceId` pour créditer
      // le lanceur (poison/feu) dans le récap, plutôt que la victime elle-même.
      let killed = false;
      for (const s of dots) {
        if (!f.alive) break;
        // Amplification du DoT si la source possède dot_amp pour ce statut (Toxine).
        let dmg = s.dmgPerTurn;
        const src = byId.get(s.sourceId);
        if (src) {
          let amp = 0;
          for (const a of abilitiesOf(src, 'dot_amp')) {
            if (a.kind === 'dot_amp' && a.status === s.type) amp += a.bonus;
          }
          if (amp > 0) dmg = Math.max(1, Math.round(dmg * (1 + amp)));
        }
        const label = s.type === 'burn' ? 'de feu' : 'de poison';
        f.hp = Math.max(0, f.hp - dmg);
        events.push({
          type: 'attack',
          round,
          actorId: f.id,
          targetId: f.id,
          sourceId: s.sourceId,
          status: s.type,
          damage: dmg,
          targetHpAfter: f.hp,
          message: `${f.name} subit ${dmg} dégâts ${label}`,
        });
        if (f.hp === 0) {
          killOrRevive(f);
          killed = true;
          break;
        }
      }
      if (killed) continue;
      // Contagion : chaque DoT dont la source possède "contagion" peut se
      // propager à un autre ennemi du même camp qui n'a pas encore ce statut.
      for (const s of f.statuses) {
        if (s.dmgPerTurn <= 0 || s.turnsLeft <= 0) continue;
        const source = byId.get(s.sourceId);
        const chance = source ? contagionOf(source) : 0;
        if (chance <= 0 || rng.next() >= chance) continue;
        const candidate = livingOnSide(fighters, f.side).find(
          (o) => o.id !== f.id && !hasStatus(o, s.type),
        );
        if (candidate) spreads.push({ target: candidate, status: { ...s } });
      }
    }
    for (const sp of spreads) applyStatusRaw(sp.target, sp.status);

    for (const actor of turnOrder(fighters)) {
      if (!actor.alive) continue;
      if (sideCleared('ally') || sideCleared('enemy')) break;

      // Étourdissement : saute le tour, consomme une charge de stun.
      const stun = actor.statuses.find((s) => s.type === 'stun' && s.turnsLeft > 0);
      if (stun) {
        stun.turnsLeft -= 1;
        events.push({
          type: 'status',
          round,
          combatantId: actor.id,
          status: 'stun',
          message: `${actor.name} est étourdi et passe son tour`,
        });
        continue;
      }

      // Provocation (tank) : tous les N tours, force les ennemis à le cibler
      // pendant `duration` tours. Action gratuite : le combattant attaque quand même.
      const taunt = abilitiesOf(actor, 'taunt').find(
        (a) => a.kind === 'taunt' && a.everyRounds > 0 && round % a.everyRounds === 0,
      );
      if (taunt && taunt.kind === 'taunt') {
        const existing = actor.statuses.find((s) => s.type === 'taunt');
        if (existing) existing.turnsLeft = Math.max(existing.turnsLeft, taunt.duration);
        else
          actor.statuses.push({
            type: 'taunt',
            turnsLeft: taunt.duration,
            dmgPerTurn: 0,
            weaken: 0,
            sourceName: actor.name,
            sourceId: actor.id,
          });
        events.push({
          type: 'status',
          round,
          combatantId: actor.id,
          status: 'taunt',
          message: `${actor.name} provoque les ennemis`,
        });
      }

      const enemySide: Side = actor.side === 'ally' ? 'enemy' : 'ally';

      // Abilité active prête (autocast à cooldown) : prioritaire sur l'attaque.
      const ready = abilitiesOf(actor, 'autocast').find(
        (a) => a.kind === 'autocast' && a.everyRounds > 0 && round % a.everyRounds === 0,
      );
      if (ready && runAutocast(actor, ready, enemySide)) continue;

      // Soigneur : soigne l'allié le plus blessé s'il y en a un, sinon attaque.
      if (actor.role === 'healer') {
        const healTarget = pickHealTarget(livingOnSide(fighters, actor.side));
        if (healTarget) {
          const base = Math.round(effectiveAtk(actor) * HEAL_MULTIPLIER);
          const rolled = Math.max(1, Math.round(base * rng.variance(DAMAGE_VARIANCE)));
          const newHp = Math.min(healTarget.maxHp, healTarget.hp + rolled);
          const amount = newHp - healTarget.hp;
          healTarget.hp = newHp;
          events.push({
            type: 'heal',
            round,
            actorId: actor.id,
            targetId: healTarget.id,
            amount,
            targetHpAfter: healTarget.hp,
            message: `${actor.name} soigne ${healTarget.name} de ${amount} PV`,
          });
          continue;
        }
      }

      // Les ennemis frappent au hasard ; tes héros gardent le focus fire.
      const target = pickTarget(livingOnSide(fighters, enemySide), actor.side === 'enemy', rng);
      if (!target) break;

      basicAttack(actor, target);

      // Multi-cibles (Volée) : frappe des cibles supplémentaires.
      const multi = abilitiesOf(actor, 'multi_shot').find((a) => a.kind === 'multi_shot');
      if (multi && multi.kind === 'multi_shot' && rng.next() < multi.chance) {
        const extras = livingOnSide(fighters, enemySide).filter((t) => t.id !== target.id);
        for (let k = 0; k < multi.extraTargets && k < extras.length; k++) {
          if (sideCleared(enemySide)) break;
          basicAttack(actor, extras[k]!);
        }
      }
    }

    // Fin de manche : décrémente les durées des DoT/weaken/buffs, purge l'expiré.
    for (const f of fighters) {
      for (const s of f.statuses) if (s.type !== 'stun') s.turnsLeft -= 1;
      f.statuses = f.statuses.filter((s) => s.turnsLeft > 0);
      for (const b of f.buffs) b.turnsLeft -= 1;
      f.buffs = f.buffs.filter((b) => b.turnsLeft > 0);
    }
  }

  const result = sideCleared('enemy') ? 'win' : 'loss';
  events.push({
    type: 'end',
    round,
    result,
    message: result === 'win' ? 'Victoire !' : 'Défaite…',
  });

  const finalState: CombatantFinalState[] = fighters.map((f) => ({
    id: f.id,
    name: f.name,
    side: f.side,
    hp: f.hp,
    maxHp: f.maxHp,
    alive: f.alive,
  }));

  return { result, seed: input.seed, rounds: round, events, finalState };
}

/**
 * Types du simulateur de combat. Framework-free, partagé front + Edge Function.
 */

export type CombatRole = 'tank' | 'dps' | 'healer' | 'enemy';

export type Side = 'ally' | 'enemy';

/** Passifs procurés par les bijoux (gemmes). Valeur = fraction (0.12 = 12 %). */
export type PassiveType =
  | 'regen' // récupère X% des PV max à chaque tour
  | 'shield' // réduit les dégâts subis de X%
  | 'crit' // X% de chance d'infliger un coup critique (dégâts ×2)
  | 'venom' // +X% de dégâts contre les ennemis déjà blessés
  | 'rage' // +X% de dégâts sous 50 % de PV
  | 'thorns' // renvoie X% des dégâts subis
  | 'lifesteal' // soigne X% des dégâts infligés
  | 'first_strike' // +X% de dégâts au premier tour
  | 'dodge' // X% de chance d'esquiver une attaque
  | 'execute'; // +X% de dégâts contre les cibles sous 30 % de PV

export type CombatPassive = { type: PassiveType; value: number };

/* ------------------------------------------------------------- ABILITÉS -- */

/** Statuts appliqués en combat (par les abilités). */
export type StatusType =
  | 'poison' // DoT (dégâts par tour)
  | 'burn' // DoT de feu (se propage via l'AOE mage)
  | 'stun' // saute son tour
  | 'weaken' // ATK & DEF réduites
  | 'taunt'; // provocation : les ennemis sont forcés de cibler le porteur

/** Action lancée par une abilité active (autocast). */
/** Compteur cumulable posé sur une cible (feu empilable, marque arcanique). */
export type MarkType = 'burn' | 'arcane';

export type AutocastAction =
  | {
      type: 'aoe';
      /** Dégâts = ATK × dmgMult sur chaque ennemi. */
      dmgMult: number;
      /** Statut optionnel appliqué aux cibles touchées. */
      status?: StatusType;
      statusChance?: number;
      statusPotency?: number;
      statusDuration?: number;
      /** Propage le burn aux autres ennemis déjà en feu (mage de feu). */
      spread?: boolean;
      /** Pose aussi une stack de marque sur chaque cible touchée. */
      mark?: MarkType;
    }
  | {
      type: 'stun_all';
      duration: number;
      /** Dégâts optionnels infligés en même temps (frappe divine). */
      dmgMult?: number;
    }
  | {
      // Frappe unique et brutale sur la cible focus (plus bas PV).
      type: 'nuke';
      dmgMult: number;
      status?: StatusType;
      statusPotency?: number;
      statusDuration?: number;
      /** Pose une stack de marque sur la cible. */
      mark?: MarkType;
    }
  | {
      // Dégâts = min(PV max de la cible × pct, ATK × capMult). Anti one-shot des boss.
      type: 'pct_hp';
      pct: number;
      capMult: number;
    }
  | {
      // Frappe TOUS les ennemis `hits` fois d'affilée (dégâts réduits par coup).
      type: 'multi_hit';
      hits: number;
      dmgMult: number;
    }
  | {
      // Fait exploser les stacks de marque sur tous les ennemis (dégâts + reset).
      type: 'detonate_all';
      mark: MarkType;
      dmgMult: number;
    }
  | {
      // Soin de zone sur les alliés (soigneur).
      type: 'heal_all';
      pct: number;
    }
  | {
      // Applique un buff temporaire (soi ou toute l'équipe) pendant `duration` tours.
      type: 'buff';
      scope: 'self' | 'team';
      duration: number;
      atk?: number; // +fraction ATK
      def?: number; // +fraction DEF
      speed?: number; // +fraction vitesse
      dmg?: number; // +fraction de dégâts infligés
      reduce?: number; // fraction de dégâts subis en moins
      thornsMult?: number; // multiplicateur des épines (0.0 = inchangé, 1.0 = ×2)
      reflect?: number; // renvoi plat des dégâts subis (1.0 = 100 %)
    }
  | {
      // Toute l'équipe (même les alliés à terre) rejoue une attaque.
      type: 'extra_turn';
    }
  | {
      // Frappe la cible focus ; mort instantanée sous un seuil de PV.
      type: 'execute_strike';
      dmgMult: number;
      instakillPct: number;
    };

/**
 * Abilité portée par un combattant (dérivée des compétences de classe ou de la
 * config ennemie). Union discriminée par `kind` — data-driven, pur.
 */
export type Ability =
  | { kind: 'armor_pen'; value: number } // ignore `value` (fraction) de la DEF
  | {
      kind: 'on_hit';
      status: StatusType;
      chance: number;
      /** Sens selon le statut : DoT = fraction de l'ATK/tour ; weaken = fraction de réduction. */
      potency: number;
      duration: number;
    }
  | { kind: 'multi_shot'; chance: number; extraTargets: number }
  | { kind: 'amp_vs_status'; status: StatusType; bonus: number } // +bonus fraction de dégâts
  | { kind: 'autocast'; everyRounds: number; action: AutocastAction }
  | { kind: 'revive'; hpPct: number } // ressuscite une fois par combat
  | { kind: 'contagion'; chance: number } // tes DoT se propagent à un autre ennemi
  | { kind: 'taunt'; everyRounds: number; duration: number } // provoque : force les ennemis à te cibler
  | {
      // Bonus de stat permanent appliqué au setup. scope 'team' = tous les alliés
      // (aura), 'self' = le porteur seul. value = fraction (0.1 = +10 %).
      kind: 'stat_mod';
      scope: 'self' | 'team';
      stat: 'atk' | 'def' | 'hp';
      value: number;
    }
  | { kind: 'stack_on_hit'; mark: MarkType; chance: number; max: number } // pose une stack à l'attaque
  | { kind: 'amp_per_stack'; mark: MarkType; bonus: number } // +bonus dégâts par stack sur la cible
  | { kind: 'detonate'; mark: MarkType; threshold: number; dmgMult: number } // explose au seuil de stacks
  | { kind: 'immune'; chance: number; statuses?: StatusType[] } // chance d'ignorer un statut négatif subi
  | { kind: 'heal_aura'; pct: number } // soigne l'allié le plus bas de pct des PV max / tour
  | { kind: 'heal_amp'; bonus: number } // +bonus sur les soins émis
  | { kind: 'ally_shield'; chance: number; pct: number } // chance de poser une barrière sur l'allié le plus bas
  | { kind: 'barrier'; pct: number } // barrière absorbante regénérée chaque tour (pct des PV max)
  | { kind: 'delayed_buff'; afterRounds: number; dmg: number } // après N tours, +dégâts à toute l'équipe (jusqu'à la fin)
  | { kind: 'threat'; value: number } // génère de l'agressivité : plus de chances d'être ciblé
  | { kind: 'dot_amp'; status: StatusType; bonus: number } // +bonus aux dégâts sur la durée du statut
  | { kind: 'heal_buff'; atk: number; duration: number } // soigner un allié bas en PV lui donne de l'ATK
  | { kind: 'riposte_shield'; bonus: number } // renvoie une attaque quand ta barrière est brisée
  | { kind: 'team_hot'; chance: number; pct: number; duration: number }; // chance de poser un soin sur la durée à l'équipe

/** Combattant tel que fourni en entrée (stats déjà "effectives"). */
export type CombatantInput = {
  id: string;
  name: string;
  role: CombatRole;
  /** PV max. Sert aussi de PV de départ, sauf si `startHp` est fourni. */
  hp: number;
  /**
   * PV de départ, si différent de `hp` (PV max). Défaut = `hp` (combattant plein).
   * Utilisé par les donjons pour enchaîner des combats sans reset des PV.
   */
  startHp?: number;
  atk: number;
  def: number;
  speed: number;
  /** Réduction plate de dégâts (armure), distincte de la DEF ; ciblée par armor_pen. */
  armor?: number;
  /** Passifs (bijoux) — optionnels. */
  passives?: CombatPassive[];
  /** Abilités actives/procs (compétences de classe ou ennemi) — optionnelles. */
  abilities?: Ability[];
};

export type CombatInput = {
  allies: CombatantInput[];
  enemies: CombatantInput[];
  seed: number;
  /** Sécurité anti-combat infini. Défaut : 100. */
  maxRounds?: number;
};

export type CombatEvent =
  | {
      type: 'attack';
      round: number;
      actorId: string;
      targetId: string;
      /**
       * Auteur réel des dégâts pour l'attribution (récap). Pour une attaque
       * classique, c'est `actorId`. Pour un tic de DoT (poison/feu), `actorId`
       * vaut la victime elle-même ; `sourceId` désigne alors le lanceur du statut.
       */
      sourceId?: string;
      /** Renseigné pour les tics de DoT (poison/feu) : type de statut à l'origine. */
      status?: StatusType;
      damage: number;
      targetHpAfter: number;
      message: string;
    }
  | {
      type: 'heal';
      round: number;
      actorId: string;
      targetId: string;
      amount: number;
      targetHpAfter: number;
      message: string;
    }
  | {
      type: 'death';
      round: number;
      combatantId: string;
      message: string;
    }
  | {
      // Événement informatif (statut appliqué, étourdissement, cast d'ultime,
      // armure brisée…). Ne modifie pas de PV — les dégâts/soins passent par
      // 'attack'/'heal' pour que l'UI reconstruise les barres de vie.
      type: 'status';
      round: number;
      combatantId: string;
      status?: StatusType;
      message: string;
    }
  | {
      type: 'end';
      round: number;
      result: CombatResultKind;
      message: string;
    };

export type CombatResultKind = 'win' | 'loss';

/** État final d'un combattant (pour l'UI / le calcul de survie). */
export type CombatantFinalState = {
  id: string;
  name: string;
  side: Side;
  hp: number;
  maxHp: number;
  alive: boolean;
};

export type CombatResult = {
  result: CombatResultKind;
  seed: number;
  rounds: number;
  events: CombatEvent[];
  finalState: CombatantFinalState[];
};

/**
 * Donjon : un enchaînement de combats consécutifs (monstres normaux, mini-boss,
 * boss final) SANS reset complet des PV entre chaque combat. Entre deux combats,
 * les survivants récupèrent une fraction de leurs PV max (regen partielle) ;
 * les statuts temporaires disparaissent (chaque combat repart d'un état neuf).
 *
 * Fonction PURE et déterministe (mêmes inputs → mêmes outputs), rejouable depuis
 * la seed. Aucune I/O, aucun accès réseau/DB. Réutilise le moteur /shared/combat.
 */
import { resolveCombat } from '../combat/resolveCombat.ts';
import { createRng } from '../combat/prng.ts';
import { scaleMinibossMonster, scaleNormalMonster, withStunImmunity } from '../combat/difficulty.ts';
import type { Rng } from '../combat/prng.ts';
import type { CombatantInput, CombatResult } from '../combat/types.ts';

/** Un combattant (monstre, mini-boss ou boss), stats de base. */
export type MonsterTemplate = {
  name: string;
  hp: number;
  atk: number;
  def: number;
  speed: number;
};

/** Un combat de la séquence : un GROUPE d'ennemis (pack de mobs, boss + gardes…). */
export type DungeonFightDef = {
  /** Libellé du combat ("Meute de goules", "Le Roi Déchu"…). */
  name: string;
  enemies: MonsterTemplate[];
};

/** Une entrée de table de loot : chance de dropper `min..max` d'une ressource. */
export type LootEntry = {
  resource: string;
  min: number;
  max: number;
  /** Probabilité de drop (0..1). */
  chance: number;
};

/** Configuration d'un type de donjon (miroir de la table `dungeon_types`). */
export type DungeonType = {
  id: string;
  name: string;
  tier: number;
  monsterSequence: DungeonFightDef[];
  /** PV récupérés entre deux combats, en fraction des PV max (0.10 = +10 %). */
  regenPctBetweenFights: number;
  /** Index (0-based) des mini-boss dans `monsterSequence`. */
  minibossIndices: number[];
  /** Index (0-based) du boss final dans `monsterSequence`. */
  bossIndex: number;
  lootTableNormal: LootEntry[];
  lootTableMiniboss: LootEntry[];
  lootTableBoss: LootEntry[];
};

/* ----------------------------------------------------------- COOLDOWN ---- */
// Un donjon est une activité « spéciale » (hors carte) : contrairement au farm
// idle continu, il impose un temps de repos avant de pouvoir le relancer. Le
// cooldown croît avec la difficulté (tier). Calculé côté serveur (anti-triche) ET
// côté client (affichage) à partir du timestamp du dernier run — d'où le partage.

/** Cooldown de base d'un donjon (tier 1), en secondes. */
export const DUNGEON_COOLDOWN_BASE_SECONDS = 10 * 60;

/** Cooldown d'un donjon selon sa difficulté : +base par tier (T1 = 10 min, T4 = 40 min). */
export function dungeonCooldownSeconds(tier: number): number {
  return DUNGEON_COOLDOWN_BASE_SECONDS * Math.max(1, Math.round(tier));
}

/**
 * Secondes restantes avant de pouvoir relancer un donjon de ce tier.
 * `lastRunAtMs` = timestamp du dernier run de CE donjon (null si jamais joué).
 */
export function dungeonCooldownRemaining(
  lastRunAtMs: number | null,
  tier: number,
  nowMs: number,
): number {
  if (lastRunAtMs == null) return 0;
  const elapsed = (nowMs - lastRunAtMs) / 1000;
  return Math.max(0, Math.ceil(dungeonCooldownSeconds(tier) - elapsed));
}

export type DungeonFightKind = 'normal' | 'miniboss' | 'boss';

/** Résultat d'un combat de la séquence (pour le replay). */
export type DungeonFightResult = {
  index: number;
  kind: DungeonFightKind;
  enemyName: string;
  /** PV des alliés engagés au DÉBUT du combat (après regen inter-combat). */
  hpBefore: { id: string; hp: number; maxHp: number }[];
  combat: CombatResult;
};

/** Une ressource lootée, agrégée sur tout le run. */
export type DungeonLootDrop = { resource: string; amount: number };

export type DungeonRunResult = {
  fightResults: DungeonFightResult[];
  success: boolean;
  /** Index du dernier combat atteint (engagé), boss compris. -1 si aucun. */
  reachedIndex: number;
  lootRolled: DungeonLootDrop[];
};

/** Nature d'un combat selon sa position dans la séquence. */
function fightKind(dungeon: DungeonType, index: number): DungeonFightKind {
  if (index === dungeon.bossIndex) return 'boss';
  if (dungeon.minibossIndices.includes(index)) return 'miniboss';
  return 'normal';
}

/** Roll d'une table de loot dans un accumulateur (déterministe via `rng`). */
function rollLootInto(acc: Map<string, number>, table: LootEntry[], rng: Rng): void {
  for (const entry of table) {
    if (rng.next() < entry.chance) {
      const qty = rng.int(entry.min, entry.max);
      if (qty > 0) acc.set(entry.resource, (acc.get(entry.resource) ?? 0) + qty);
    }
  }
}

/**
 * Simule un run de donjon complet.
 * @param seed   seed serveur (jamais fournie par le client).
 * @param squad  combattants prêts (stats effectives, `hp` = PV max).
 * @param dungeon configuration du donjon.
 */
export function simulateDungeonRun(
  seed: number,
  squad: CombatantInput[],
  dungeon: DungeonType,
): DungeonRunResult {
  const fightResults: DungeonFightResult[] = [];
  const loot = new Map<string, number>();
  // rng de loot dérivé de la seed (indépendant des seeds de combat).
  const lootRng = createRng((seed ^ 0x9e3779b9) >>> 0);

  // PV courants par héros (démarrent au max = squad[i].hp).
  const currentHp = new Map<string, number>(squad.map((h) => [h.id, h.hp]));
  const maxHp = new Map<string, number>(squad.map((h) => [h.id, h.hp]));

  let combatSeed = seed >>> 0;
  let reachedIndex = -1;
  let success = false;

  for (let i = 0; i < dungeon.monsterSequence.length; i++) {
    // Alliés engagés = survivants (PV > 0), avec leurs PV courants en `startHp`.
    const allies: CombatantInput[] = squad
      .filter((h) => (currentHp.get(h.id) ?? 0) > 0)
      .map((h) => ({ ...h, startHp: currentHp.get(h.id)! }));

    // Sécurité : plus personne debout → wipe (ne devrait pas arriver ici, le wipe
    // est détecté en fin de combat, mais on protège contre une séquence vide).
    if (allies.length === 0) break;

    const fight = dungeon.monsterSequence[i]!;
    const kind = fightKind(dungeon, i);
    const enemies: CombatantInput[] = fight.enemies.map((m, k) => {
      const base: CombatantInput = {
        id: `enemy-${i}-${k}`,
        name: m.name,
        role: 'enemy',
        hp: m.hp,
        atk: m.atk,
        def: m.def,
        speed: m.speed,
      };
      // Boss : insensible au stun (stats inchangées). Mobs classiques et
      // mini-boss : renforcés (les mini-boss plus légèrement).
      if (kind === 'boss') return withStunImmunity(base);
      if (kind === 'miniboss') return scaleMinibossMonster(base);
      return scaleNormalMonster(base);
    });

    combatSeed = (Math.imul(combatSeed, 1664525) + 1013904223) >>> 0;
    const combat = resolveCombat({ allies, enemies, seed: combatSeed });
    reachedIndex = i;

    fightResults.push({
      index: i,
      kind,
      enemyName: fight.name,
      hpBefore: allies.map((a) => ({ id: a.id, hp: a.startHp!, maxHp: maxHp.get(a.id)! })),
      combat,
    });

    // Report des PV de fin de combat sur les alliés engagés.
    for (const fs of combat.finalState) {
      if (fs.side === 'ally') currentHp.set(fs.id, fs.hp);
    }

    const monsterDefeated = combat.result === 'win';
    const teamAlive = combat.finalState.some((fs) => fs.side === 'ally' && fs.alive);

    // Loot : uniquement sur un combat GAGNÉ (monstre vaincu). Le loot boss n'est
    // donc rollé que si le boss est réellement battu (⇒ succès du run).
    if (monsterDefeated) {
      const table =
        kind === 'boss'
          ? dungeon.lootTableBoss
          : kind === 'miniboss'
            ? dungeon.lootTableMiniboss
            : dungeon.lootTableNormal;
      rollLootInto(loot, table, lootRng);
    }

    // Wipe : toute l'équipe à terre → arrêt, échec.
    if (!teamAlive) {
      success = false;
      break;
    }

    // Monstre non vaincu mais équipe encore debout (stalemate/timeout) : on ne
    // peut pas franchir ce combat → arrêt, échec.
    if (!monsterDefeated) {
      success = false;
      break;
    }

    // Séquence terminée (boss final vaincu) → succès.
    if (i === dungeon.monsterSequence.length - 1) {
      success = true;
      break;
    }

    // Regen partielle entre deux combats, pour les survivants (basée sur PV max).
    for (const h of squad) {
      const cur = currentHp.get(h.id) ?? 0;
      if (cur <= 0) continue; // un héros à terre le reste pour le run.
      const max = maxHp.get(h.id)!;
      if (cur >= max) continue;
      const heal = Math.round(max * dungeon.regenPctBetweenFights);
      currentHp.set(h.id, Math.min(max, cur + heal));
    }
  }

  const lootRolled: DungeonLootDrop[] = [...loot.entries()].map(([resource, amount]) => ({
    resource,
    amount,
  }));

  return { fightResults, success, reachedIndex, lootRolled };
}

/**
 * Formules de progression pures (stats effectives, XP, puissance).
 * Partagé front + Edge Function. La croissance +5%/niveau est répliquée
 * (en approximation) dans la vue SQL `leaderboard`.
 */

export type BaseStats = {
  hp: number;
  atk: number;
  def: number;
  speed: number;
};

export type ItemBonuses = {
  atk: number;
  def: number;
  hp: number;
};

export type EffectiveStats = BaseStats;

export const LEVEL_GROWTH = 0.05;
const XP_PER_LEVEL = 100;
/** Croissance exponentielle du coût d'un niveau (+12 % composés par niveau). */
const XP_CURVE = 1.12;
const XP_REWARD_PER_DIFFICULTY = 40;

export type StatKey = 'hp' | 'atk' | 'def' | 'speed';

/**
 * Points de compétence octroyés par niveau gagné (dépensés dans l'arbre de la
 * classe, à la Bibliothèque du Savoir). Les stats, elles, montent
 * automatiquement via la croissance +5 %/niveau (`LEVEL_GROWTH`).
 */
export const SKILL_POINTS_PER_LEVEL = 1;

/** Gain de stat par point dépensé (allocation manuelle historique, gelée). */
export const STAT_PER_POINT: Record<StatKey, number> = { hp: 8, atk: 2, def: 2, speed: 1 };

/** Points dépensés par stat (bruts). */
export type Allocation = { hp: number; atk: number; def: number; speed: number };

/** Bonus plats issus de l'arbre de compétence (par stat). */
export type SkillBonuses = { hp: number; atk: number; def: number; speed: number };

const EMPTY_BONUSES: ItemBonuses = { atk: 0, def: 0, hp: 0 };
const ZERO_ALLOC: Allocation = { hp: 0, atk: 0, def: 0, speed: 0 };
const ZERO_SKILL: SkillBonuses = { hp: 0, atk: 0, def: 0, speed: 0 };

/** Stats effectives = base × (1 + 5%·(niveau−1)) + équipement + alloc + compétences. */
export function effectiveStats(
  base: BaseStats,
  level: number,
  bonuses: ItemBonuses = EMPTY_BONUSES,
  alloc: Allocation = ZERO_ALLOC,
  skill: SkillBonuses = ZERO_SKILL,
): EffectiveStats {
  const mult = 1 + LEVEL_GROWTH * (level - 1);
  return {
    hp: Math.round(base.hp * mult) + bonuses.hp + alloc.hp * STAT_PER_POINT.hp + skill.hp,
    atk: Math.round(base.atk * mult) + bonuses.atk + alloc.atk * STAT_PER_POINT.atk + skill.atk,
    def: Math.round(base.def * mult) + bonuses.def + alloc.def * STAT_PER_POINT.def + skill.def,
    speed: base.speed + alloc.speed * STAT_PER_POINT.speed + skill.speed,
  };
}

/** XP nécessaire pour passer de `level` à `level + 1` (linéaire × exponentiel). */
export function xpToNextLevel(level: number): number {
  return Math.round(XP_PER_LEVEL * level * Math.pow(XP_CURVE, level - 1));
}

export type XpGainResult = {
  level: number;
  xp: number;
  levelsGained: number;
};

/** Applique un gain d'XP en enchaînant les montées de niveau. */
export function applyXpGain(level: number, xp: number, gained: number): XpGainResult {
  let newLevel = level;
  let newXp = xp + gained;
  let levelsGained = 0;

  while (newXp >= xpToNextLevel(newLevel)) {
    newXp -= xpToNextLevel(newLevel);
    newLevel += 1;
    levelsGained += 1;
  }

  return { level: newLevel, xp: newXp, levelsGained };
}

/** XP gagné pour un donjon réussi (proportionnel à la difficulté). */
export function xpRewardForDungeon(difficulty: number): number {
  return XP_REWARD_PER_DIFFICULTY * difficulty;
}

/** Puissance d'un héros (pondération alignée sur la vue leaderboard). */
export function heroPower(stats: EffectiveStats): number {
  return Math.round(stats.atk * 2 + stats.def * 2 + stats.hp * 0.5 + stats.speed);
}

/**
 * Prêt de héros : fige un héros en SNAPSHOT lecture seule pour qu'un emprunteur
 * puisse l'utiliser sans jamais toucher au héros du propriétaire.
 *
 * Choix clé : le snapshot est EXACTEMENT un `CombatantInput` — la structure que
 * le moteur de combat (`resolveCombat`) attend déjà pour un héros normal. Un seul
 * chemin de code : héros normal et héros emprunté produisent le même type.
 * Pur et testable, partagé front + Edge Functions.
 */
import type { CombatantInput, CombatPassive } from '../combat/types.ts';
import { effectiveStats } from './formulas.ts';
import { computeAbilities, computePassives, combatRole, type LearnedSkills } from './skills.ts';

/** Ingrédients bruts d'un héros nécessaires pour reconstruire ses stats de combat. */
export type HeroSnapshotInput = {
  id: string;
  name: string;
  classId: string;
  level: number;
  /** Stats de base de la classe (hero_classes). */
  classBase: { hp: number; atk: number; def: number; speed: number };
  /** Roll de naissance (heroes.bonus_*). */
  innate: { hp: number; atk: number; def: number; speed: number };
  /** Points de stat alloués (heroes.alloc_*). */
  alloc: { hp: number; atk: number; def: number; speed: number };
  /** Somme des bonus d'équipement (arme + armure + bijou + relique). */
  equipment: { atk: number; def: number; hp: number };
  /** Passif du bijou équipé (valeur DÉJÀ en fraction), s'il y en a un. */
  jewelPassive?: CombatPassive | null;
  /** Compétences apprises (nodeId -> rang). */
  skills: LearnedSkills;
};

/**
 * Un snapshot de héros = un `CombatantInput`. On alias le type pour l'intention,
 * mais c'est bien la MÊME structure que pour un héros normal (pas de type parallèle).
 */
export type HeroSnapshot = CombatantInput;

/** Fige un héros en `CombatantInput` prêt pour `resolveCombat` (mêmes règles que le build normal). */
export function buildHeroSnapshot(h: HeroSnapshotInput): HeroSnapshot {
  const stats = effectiveStats(
    {
      hp: Math.max(1, h.classBase.hp + h.innate.hp),
      atk: Math.max(1, h.classBase.atk + h.innate.atk),
      def: Math.max(0, h.classBase.def + h.innate.def),
      speed: Math.max(1, h.classBase.speed + h.innate.speed),
    },
    h.level,
    { atk: h.equipment.atk, def: h.equipment.def, hp: h.equipment.hp },
    { hp: h.alloc.hp, atk: h.alloc.atk, def: h.alloc.def, speed: h.alloc.speed },
  );
  const passives: CombatPassive[] = [
    ...(h.jewelPassive ? [h.jewelPassive] : []),
    ...computePassives(h.classId, h.skills),
  ];
  return {
    id: h.id,
    name: h.name,
    role: combatRole(h.classId),
    ...stats,
    passives,
    abilities: computeAbilities(h.classId, h.skills),
  };
}

/**
 * Un héros n'est empruntable que s'il n'est pas déjà engagé dans une activité
 * chez son propriétaire (déploiement/farm, donjon, expédition, ou déjà prêté).
 * L'ensemble des héros engagés est calculé côté serveur (état DB) et fourni ici.
 */
export function isHeroAvailableForLoan(heroId: string, engagedHeroIds: readonly string[]): boolean {
  return !engagedHeroIds.includes(heroId);
}

