/* ------------------------------------------------------ RECETTE COMPOSÉE -- */
// Une pièce de set réunit les QUATRE sources du jeu (recette homogène) :
//   • matériaux de ZONE (carte) — base commune à tous les crafts,
//   • matériaux d'EXPÉDITION — la signature de la pièce (déjà dans `materials`),
//   • un composant de BOSS — détermine l'ENSEMBLE (un par set),
//   • un matériau de DONJON — la touche « relique » partagée.

type Mat = { key: string; qty: number };

/** Composant de boss signature de chaque ensemble (choix de l'ensemble). */
export const SET_BOSS_COMPONENT: Record<string, string> = {
  sylve: 'coeur_sylve',
  arcane: 'encre_kraken',
  stellaire: 'fragment_titan',
};

/** Matériau de zone (carte) requis par toute pièce de set. */
export const SET_ZONE_MATERIAL: Mat = { key: 'ecorce', qty: 8 };
/** Matériau de donjon requis par toute pièce de set. */
export const SET_DUNGEON_MATERIAL: Mat = { key: 'sceau_catacombe', qty: 1 };

/** Additionne les quantités par clé (évite les doublons dans une recette). */
function mergeMaterials(mats: Mat[]): Mat[] {
  const acc = new Map<string, number>();
  for (const m of mats) acc.set(m.key, (acc.get(m.key) ?? 0) + m.qty);
  return [...acc].map(([key, qty]) => ({ key, qty }));
}

/**
 * Recette complète d'une pièce de set : zone + expédition + boss (ensemble) +
 * donjon. Utilisée à l'identique côté client (affichage) et serveur (coût).
 */
export function setPieceRecipe(piece: SetPieceRecipe): { gold: number; materials: Mat[] } {
  const boss = SET_BOSS_COMPONENT[piece.setId];
  return {
    gold: piece.gold,
    materials: mergeMaterials([
      SET_ZONE_MATERIAL,
      ...piece.materials,
      ...(boss ? [{ key: boss, qty: 1 }] : []),
      SET_DUNGEON_MATERIAL,
    ]),
  };
}

/**
 * Bonus de set actifs à partir des set_id des objets équipés (weapon/armor/jewel/
 * relic). 2 pièces d'un même set → bonus2 ; 4 pièces → bonus2 + bonus4.
 */
export function computeSetBonuses(equippedSetIds: (string | null | undefined)[]): SetStatBonus {
  const counts = new Map<string, number>();
  for (const s of equippedSetIds) if (s) counts.set(s, (counts.get(s) ?? 0) + 1);
  const total: SetStatBonus = { atk: 0, def: 0, hp: 0 };
  for (const [sid, cnt] of counts) {
    const set = setById(sid);
    if (!set) continue;
    if (cnt >= 2) {
      total.atk += set.bonus2.atk;
      total.def += set.bonus2.def;
      total.hp += set.bonus2.hp;
    }
    if (cnt >= 4) {
      total.atk += set.bonus4.atk;
      total.def += set.bonus4.def;
      total.hp += set.bonus4.hp;
    }
  }
  return total;
}

/** Détail des sets actifs (pour l'affichage UI). */
export type ActiveSet = { set: ItemSet; count: number };
export function activeSets(equippedSetIds: (string | null | undefined)[]): ActiveSet[] {
  const counts = new Map<string, number>();
  for (const s of equippedSetIds) if (s) counts.set(s, (counts.get(s) ?? 0) + 1);
  const out: ActiveSet[] = [];
  for (const [sid, count] of counts) {
    const set = setById(sid);
    if (set && count >= 2) out.push({ set, count });
  }
  return out;
}

/**
 * Arbres de compétence par classe (Bibliothèque du Savoir) — refonte 3 branches.
 *
 * Chaque classe a 3 BRANCHES autonomes, chacune de 5 nœuds :
 *   3 passifs (rang max 5) + 1 actif (rang max 3) + 1 ultime (rang max 2) = 20 pts/branche.
 * Un nœud n'accorde JAMAIS de stat brute : uniquement des EFFETS SPÉCIAUX (passif de
 * combat ou abilité/proc). Le capstone (ultime) ne se débloque qu'après 15 pts investis
 * DANS sa branche → spécialisation forcée. Pur, partagé front + Edge.
 *
 * Déploiement en phases : les nœuds dont le mécanisme n'existe pas encore dans le moteur
 * sont marqués `pending` (visibles mais pas encore apprenables). Ils s'allumeront au fil
 * des phases (auras, soins, stacks, défense réactive, dégâts spéciaux…).
 */
import type { Ability, AutocastAction, CombatPassive, CombatRole, MarkType, PassiveType, StatusType } from '../combat/types.ts';

export type ClassId = 'guerrier' | 'archer' | 'mage' | 'paladin' | 'soigneur';

/** Rôle de combat (comportement d'IA) dérivé de la classe. */
export function combatRole(classId: string): CombatRole {
  if (classId === 'soigneur') return 'healer';
  if (classId === 'guerrier' || classId === 'paladin') return 'tank';
  return 'dps';
}

/** Emplacement d'un nœud dans sa branche (dicte le rang max & le coût). */
export type NodeSlot = 'passive' | 'active' | 'ultimate';

/** Rang max par type d'emplacement. */
export const SLOT_MAX_RANK: Record<NodeSlot, number> = { passive: 5, active: 3, ultimate: 2 };

/** Points à investir DANS une branche avant de pouvoir toucher son ultime. */
export const ULTIMATE_GATE = 15;

/** Coût en or d'un reset, par point de compétence dépensé. */
export const RESET_GOLD_PER_POINT = 50;

/** Coût total d'un reset pour `spent` points dépensés. */
export function resetCost(spent: number): number {
  return Math.max(0, spent) * RESET_GOLD_PER_POINT;
}

/**
 * Gabarit d'abilité porté par un nœud : valeur concrète = base + perRank × rang.
 * (Les champs non pertinents pour un `kind` sont ignorés.)
 */
export type AbilitySpec = {
  kind: Ability['kind'];
  status?: StatusType;
  chance?: number;
  chancePerRank?: number;
  potency?: number;
  potencyPerRank?: number;
  duration?: number;
  durationPerRank?: number;
  value?: number;
  valuePerRank?: number;
  bonus?: number;
  bonusPerRank?: number;
  extraTargets?: number;
  everyRounds?: number;
  everyRoundsPerRank?: number;
  action?: AutocastAction;
  hpPct?: number;
  scope?: 'self' | 'team';
  stat?: 'atk' | 'def' | 'hp';
  mark?: MarkType;
  max?: number;
  threshold?: number;
  pct?: number;
  statuses?: StatusType[];
  afterRounds?: number;
};

/** Gabarit de passif de combat : valeur (fraction) = value + valuePerRank × rang. */
export type PassiveSpec = { type: PassiveType; value?: number; valuePerRank?: number };

export type SkillNode = {
  id: string;
  branch: 1 | 2 | 3;
  slot: NodeSlot;
  name: string;
  desc: string;
  icon: string;
  maxRank: number;
  /** Effet pas encore implémenté dans le moteur → non apprenable pour l'instant. */
  pending?: boolean;
  /** Passifs de combat accordés (montent avec le rang). */
  passives?: PassiveSpec[];
  /** Abilités actives/procs accordées (montent avec le rang). */
  abilities?: AbilitySpec[];
};

export type SkillBranch = { id: 1 | 2 | 3; name: string; color: string; nodes: SkillNode[] };

/** État appris d'un héros : map nodeId → rang courant. */
export type LearnedSkills = Record<string, number>;

/* --------------------------------------------------------------- helpers -- */

const passive = (
  id: string,
  branch: 1 | 2 | 3,
  name: string,
  icon: string,
  desc: string,
  effect: { passives?: PassiveSpec[]; abilities?: AbilitySpec[] } | 'pending',
): SkillNode => ({
  id, branch, slot: 'passive', name, icon, desc, maxRank: SLOT_MAX_RANK.passive,
  ...(effect === 'pending' ? { pending: true } : effect),
});
const active = (
  id: string,
  branch: 1 | 2 | 3,
  name: string,
  icon: string,
  desc: string,
  effect: { passives?: PassiveSpec[]; abilities?: AbilitySpec[] } | 'pending',
): SkillNode => ({
  id, branch, slot: 'active', name, icon, desc, maxRank: SLOT_MAX_RANK.active,
  ...(effect === 'pending' ? { pending: true } : effect),
});
